        db.on('load', function(length) {
            assert.strictEqual(length, 0);
            assert.strictEqual(db.size(), 0);
            done();
        });
    });

    it('should set and get values in memory', function(done) {
        const db = new dirty.Dirty();

        db.on('load', function() {
            db.set('key1', {name: 'test'});
            const result = db.get('key1');
            assert.deepStrictEqual(result, {name: 'test'});
            assert.strictEqual(db.size(), 1);
            done();
        });
    });

    it('should remove values using rm method', function(done) {
        const db = new dirty.Dirty();

        db.on('load', function() {
            db.set('key1', {name: 'test'});
            assert.strictEqual(db.size(), 1);

            db.rm('key1', function() {
                assert.strictEqual(db.get('key1'), undefined);
                assert.strictEqual(db.size(), 0);
                done();
            });
        });
    });

    it('should iterate over keys with forEach', function(done) {
        const db = new dirty.Dirty();

        db.on('load', function() {
            db.set('key1', {value: 1});
            db.set('key2', {value: 2});

            const found = [];
            db.forEach(function(key, val) {
                found.push({key, val});
            });

            assert.strictEqual(found.length, 2);
            assert.strictEqual(found.some(item => item.key === 'key1' && item.val.value === 1), true);
            assert.strictEqual(found.some(item => item.key === 'key2' && item.val.value === 2), true);
            done();
        });
    });

    it('should update existing values', function(done) {
        const db = new dirty.Dirty();

        db.on('load', function() {
            db.set('counter', {count: 1});

            db.update('counter', function(val) {
                return {count: val.count + 1};
            }, function() {
                const result = db.get('counter');
                assert.deepStrictEqual(result, {count: 2});
                done();
            });
        });
    });

    it('should persist data to disk', function(done) {
        const db = new dirty.Dirty(dbPath);

        db.on('load', function() {
            db.set('persistent', {data: 'test'}, function() {
                // Close the database
                db.close();

                // Create a new instance to verify persistence
                const db2 = new dirty.Dirty(dbPath);
                db2.on('load', function(length) {
                    assert.strictEqual(length, 1);
                    const result = db2.get('persistent');
                    assert.deepStrictEqual(result, {data: 'test'});
                    db2.close();
                    done();
                });
            });
        });
    });

    it('should handle non-existent file gracefully', function(done) {
        const nonExistentPath = path.join(tempDir, 'nonexistent.db');
        const db = new dirty.Dirty(nonExistentPath);

        db.on('load', function(length) {
            assert.strictEqual(length, 0);
            assert.strictEqual(db.size(), 0);
            db.close();
            done();
        });
    });

    it('should emit drain event after all writes complete', function(done) {
        const db = new dirty.Dirty();
        let drainEmitted = false;

        db.on('drain', function() {
            drainEmitted = true;
        });

        db.on('load', function() {
            db.set('key1', {test: 1});
            db.set('key2', {test: 2});

            setTimeout(function() {
                assert.strictEqual(drainEmitted, true);
                done();
            }, 10);
        });
    });
});
